import{_ as t,o,c as i,ag as r}from"./chunks/framework.DwYrYzXn.js";const m=JSON.parse('{"title":"Tempo Premium Plugin: Contributor Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"plan/contributor-workflow.md","filePath":"plan/contributor-workflow.md"}'),a={name:"plan/contributor-workflow.md"};function n(s,e,l,c,p,u){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="tempo-premium-plugin-contributor-workflow" tabindex="-1">Tempo Premium Plugin: Contributor Workflow <a class="header-anchor" href="#tempo-premium-plugin-contributor-workflow" aria-label="Permalink to &quot;Tempo Premium Plugin: Contributor Workflow&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To protect the intellectual property (IP) of all premium plugin developers while maintaining an excellent Developer Experience (DX), Magma Computing Solutions utilizes a <strong>&quot;Bring Your Own Repo&quot; (BYOR)</strong> architecture.</p><p>Because GitHub does not support folder-level read access, contributors cannot be invited directly to the <code>tempo-plugin</code> monorepo (as this would expose everyone else&#39;s proprietary code). Instead, contributors develop their plugins in isolated repositories and grant Magma Computing Solutions access for code review, integration, and publication.</p><hr><h2 id="the-workflow-lifecycle" tabindex="-1">The Workflow Lifecycle <a class="header-anchor" href="#the-workflow-lifecycle" aria-label="Permalink to &quot;The Workflow Lifecycle&quot;">​</a></h2><h3 id="step-1-independent-development" tabindex="-1">Step 1: Independent Development <a class="header-anchor" href="#step-1-independent-development" aria-label="Permalink to &quot;Step 1: Independent Development&quot;">​</a></h3><ol><li><strong>Repository Setup:</strong> The contributor creates their own private GitHub repository for their plugin.</li><li><strong>Development:</strong> They build and test their plugin locally against the open-source <code>@magmacomputing/tempo</code> core library.</li><li><strong>DX Ownership:</strong> During this phase, the contributor has 100% control over their own CI/CD, issue tracking, linting, and testing environments.</li></ol><h3 id="step-2-submission-and-access" tabindex="-1">Step 2: Submission and Access <a class="header-anchor" href="#step-2-submission-and-access" aria-label="Permalink to &quot;Step 2: Submission and Access&quot;">​</a></h3><p>Once the plugin is ready for its v1.0.0 release (or a subsequent version update):</p><ol><li><strong>Grant Access:</strong> The contributor invites the Magma Computing Solutions administrative team to their private repository as a Collaborator (or alternatively, transfers the repository into the Magma organization).</li><li><strong>Notification:</strong> The contributor formally notifies Magma Computing Solutions that a release candidate is ready for review.</li></ol><h3 id="step-3-magma-review-audit" tabindex="-1">Step 3: Magma Review &amp; Audit <a class="header-anchor" href="#step-3-magma-review-audit" aria-label="Permalink to &quot;Step 3: Magma Review &amp; Audit&quot;">​</a></h3><p>Upon notification, the Magma team takes over the pipeline to ensure enterprise quality:</p><ol><li><strong>Code Audit:</strong> Magma performs a strict security, performance, and architecture review of the submitted source code.</li><li><strong>Testing:</strong> Magma runs internal integration tests to ensure flawless compatibility with the current Tempo core ecosystem.</li><li><strong>Feedback:</strong> If architectural changes are required, Magma will communicate directly with the contributor via Issues or Pull Requests on the contributor&#39;s repository.</li></ol><h3 id="step-4-integration-and-publication" tabindex="-1">Step 4: Integration and Publication <a class="header-anchor" href="#step-4-integration-and-publication" aria-label="Permalink to &quot;Step 4: Integration and Publication&quot;">​</a></h3><p>Once the code passes the Magma audit:</p><ol><li><strong>Monorepo Integration:</strong> Magma securely copies the approved plugin code into a new workspace directory inside the highly restricted <code>tempo-plugin</code> monorepo.</li><li><strong>Proprietary Wrapping:</strong> Magma wraps the contributor&#39;s code in the official <code>definePremiumExtension</code> factory and attaches the proprietary licensing hooks.</li><li><strong>Publication:</strong> Magma handles the final build process and publishes the plugin securely to NPM under the official <code>@magmacomputing/tempo-plugin-[name]</code> namespace.</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Future version updates from the contributor will follow this exact same lifecycle, starting from Step 2.</p></div><hr><h2 id="ecosystem-flexibility-exit-strategy" tabindex="-1">Ecosystem Flexibility &amp; Exit Strategy <a class="header-anchor" href="#ecosystem-flexibility-exit-strategy" aria-label="Permalink to &quot;Ecosystem Flexibility &amp; Exit Strategy&quot;">​</a></h2><p>This architecture also inherently protects the contributor. Because they own their own independent repository containing the pure, unwrapped plugin logic:</p><ul><li><strong>Zero Vendor Lock-in:</strong> If a developer decides they want to pull out of the premium Magma arrangement, they can seamlessly transition out at any time.</li><li><strong>Community Transition:</strong> They simply publish their own repository directly to NPM as a standard, open-source community plugin. Because the open-source <code>tempo</code> core engine naturally accepts standard plugin registrations, their plugin will continue to work flawlessly without the <code>definePremiumExtension()</code> wrapper.</li></ul>',22)])])}const h=t(a,[["render",n]]);export{m as __pageData,h as default};
